// Add timestamp to health data
const data = $json || {};
return [{ json: { timestamp: new Date().toISOString(), ...data } }];

// Last resort: format raw data when both AI services fail
const data = $('Add Timestamp').first().json;
let lines = ['**AI summarization unavailable — raw data below**\n'];

if (data.http_checks) {
  lines.push('**Docker Services:**');
  for (const svc of data.http_checks) {
    const icon = svc.healthy ? '✅' : '❌';
    lines.push(`${icon} ${svc.service}: HTTP ${svc.status_code}`);
  }
  lines.push('');
}

if (data.disk) {
  lines.push('**Disk Usage:**');
  for (const d of data.disk) {
    lines.push(`${d.filesystem}: ${d.percent} used (${d.used}/${d.size})`);
  }
  lines.push('');
}

if (data.k3s?.nodes?.length > 0) {
  lines.push('**K3s Nodes:**');
  for (const n of data.k3s.nodes) {
    const icon = n.status === 'Ready' ? '✅' : '❌';
    lines.push(`${icon} ${n.name}: ${n.status}`);
  }
  lines.push('');
}

if (data.k3s?.unhealthy_pods?.length > 0) {
  lines.push('**Unhealthy Pods:**');
  for (const p of data.k3s.unhealthy_pods) {
    lines.push(`❌ ${p.namespace}/${p.name}: ${p.phase}`);
  }
}

return [{ json: { summary: lines.join('\n'), source: 'AI unavailable — raw data' } }];

// Build the Discord embed with color coding
const { summary, source } = $json;

let color = 3066993; // green
const lower = summary.toLowerCase();
if (lower.includes('critical') || lower.includes('down') || lower.includes('unreachable') || lower.includes('❌')) {
  color = 15158332; // red
} else if (lower.includes('warning') || lower.includes('issue') || lower.includes('expiring') || lower.includes('above 80')) {
  color = 15844367; // yellow
}

const desc = summary.length > 4000 ? summary.substring(0, 3997) + '...' : summary;

const now = new Date();
const dateStr = now.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric', timeZone: 'America/New_York' });
const timeStr = now.toLocaleTimeString('en-US', { hour: 'numeric', minute: '2-digit', timeZone: 'America/New_York' });

return [{
  json: {
    embeds: [{
      title: `Homelab Daily Report — ${dateStr}`,
      description: desc,
      color,
      footer: { text: `${source} | ${timeStr} ET` }
    }]
  }
}];
